#!/usr/bin/env bash
set -e
APP_DIR="${COM_MOBILE_DIR:-/mnt/home-storage/home/pmsa/apps/com/com-mobile}"
mkdir -p "$APP_DIR/app"
cat > "$APP_DIR/.env" <<'EOF'
EXPO_PUBLIC_API_BASE_URL=https://com.pm.sa/api
EOF
cat > "$APP_DIR/app/_layout.tsx" <<'EOF'
import { Stack } from 'expo-router';
import { StatusBar } from 'expo-status-bar';
export default function Layout(){return <><StatusBar style="dark"/><Stack screenOptions={{headerShown:false}}/></>}
EOF
cat > "$APP_DIR/app/index.tsx" <<'EOF'
import React,{useEffect,useMemo,useState}from'react';
import{ActivityIndicator,Alert,Modal,Pressable,ScrollView,StyleSheet,Text,TextInput,View}from'react-native';
const API=process.env.EXPO_PUBLIC_API_BASE_URL||'https://com.pm.sa/api';
const today=()=>new Date().toISOString().slice(0,10);
const S=[
{key:'dashboard',title:'الملخص',ep:'dashboard',fields:[]},
{key:'hetzner-costs',title:'حسابات Hetzner',ep:'hetzner-costs',fields:[['cost_date','التاريخ','date'],['cost_eur','التكلفة باليورو','number'],['cost_sar','التكلفة بالريال','number'],['notes','ملاحظات','text']]},
{key:'cpanel-server-costs',title:'سيرفر cPanel',ep:'cpanel-server-costs',fields:[['cost_date','التاريخ','date'],['cost_usd','التكلفة بالدولار','number'],['cost_sar','التكلفة بالريال','number'],['notes','ملاحظات','text']]},
{key:'expenses',title:'المصروفات',ep:'expenses',fields:[['expense_date','التاريخ','date'],['expense_type','نوع الصرف','text'],['amount_sar','المبلغ بالريال','number'],['notes','ملاحظات','text']]},
{key:'hostings',title:'الاستضافات',ep:'hostings',fields:[['company_name','اسم الشركة','text'],['domain','الدومين','text'],['current_space_mb','المساحة الحالية MB','number'],['allowed_space_mb','المساحة المسموح بها MB','number'],['domain_renewal_cost_sar','تكلفة تجديد النطاق','number'],['hosting_cost_sar','تكلفة الاستضافة','number'],['record_date','التاريخ','date'],['tax_sar','الضريبة','number'],['hosting_renewal_date','تاريخ تجديد الهوست','date'],['domain_renewal_date','تاريخ تجديد الدومين','date'],['notes','ملاحظات','text']]}
];
export default function App(){const[tab,setTab]=useState('dashboard'),[loading,setLoading]=useState(false),[data,setData]=useState<any>(null),[open,setOpen]=useState(false),[edit,setEdit]=useState<any>(null),[form,setForm]=useState<any>({});const sec=useMemo(()=>S.find(x=>x.key===tab)||S[0],[tab]);const rows=Array.isArray(data?.data)?data.data:[];const totals=data?.totals||data?.summary||{};useEffect(()=>{load()},[tab]);async function api(p:string,o:any={}){const r=await fetch(`${API}/${p}`,{headers:{Accept:'application/json','Content-Type':'application/json'},...o});const j=await r.json().catch(()=>({}));if(!r.ok)throw new Error(j.message||'تعذر تنفيذ الطلب');return j}async function load(){setLoading(true);try{setData(await api(sec.ep))}catch(e:any){Alert.alert('خطأ',e.message||'تعذر الاتصال')}finally{setLoading(false)}}function blank(){const f:any={};sec.fields.forEach((x:any)=>f[x[0]]=x[2]==='date'?today():'');return f}function add(){setEdit(null);setForm(blank());setOpen(true)}function startEdit(r:any){const f=blank();sec.fields.forEach((x:any)=>f[x[0]]=r[x[0]]==null?'':String(r[x[0]]));setEdit(r);setForm(f);setOpen(true)}async function save(){try{const b:any={...form};sec.fields.forEach((x:any)=>{if(x[2]==='number'&&(b[x[0]]===''||b[x[0]]==null))b[x[0]]='0'});if(edit?.id)await api(`${sec.ep}/${edit.id}`,{method:'PUT',body:JSON.stringify(b)});else await api(sec.ep,{method:'POST',body:JSON.stringify(b)});setOpen(false);load()}catch(e:any){Alert.alert('تعذر الحفظ',e.message||'راجع البيانات')}}async function del(r:any){Alert.alert('حذف','هل تريد حذف السجل؟',[{text:'إلغاء'},{text:'حذف',style:'destructive',onPress:async()=>{try{await api(`${sec.ep}/${r.id}`,{method:'DELETE'});load()}catch(e:any){Alert.alert('خطأ',e.message)}}}])}return <View style={st.screen}><View style={st.head}><Text style={st.title}>COM</Text><Text style={st.sub}>إدارة السيرفر والاستضافات</Text></View><ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={st.tabs}>{S.map(x=><Pressable key={x.key} onPress={()=>setTab(x.key)} style={[st.tab,tab===x.key&&st.tabOn]}><Text style={[st.tabText,tab===x.key&&st.tabTextOn]}>{x.title}</Text></Pressable>)}</ScrollView><View style={st.bar}><View><Text style={st.h}>{sec.title}</Text><Text style={st.url}>{API}/{sec.ep}</Text></View>{tab!=='dashboard'?<Pressable onPress={add} style={st.add}><Text style={st.addText}>+ إضافة</Text></Pressable>:<Pressable onPress={load} style={st.add}><Text style={st.addText}>تحديث</Text></Pressable>}</View>{loading?<View style={st.loading}><ActivityIndicator/><Text>جاري التحميل...</Text></View>:<ScrollView contentContainerStyle={st.content}>{tab==='dashboard'?Object.entries(totals).map(([k,v])=><Card key={k} title={k} value={String(v??0)}/>):rows.length?rows.map((r:any)=><View key={r.id} style={st.card}>{Object.entries(r).slice(0,8).map(([k,v])=><View key={k} style={st.row}><Text style={st.k}>{k}</Text><Text style={st.v}>{String(v??'-')}</Text></View>)}<View style={st.actions}><Pressable onPress={()=>del(r)} style={st.secondary}><Text style={st.secondaryText}>حذف</Text></Pressable><Pressable onPress={()=>startEdit(r)} style={st.primary}><Text style={st.primaryText}>تعديل</Text></Pressable></View></View>):<Text style={st.empty}>لا توجد بيانات بعد</Text>}</ScrollView>}<Modal visible={open} animationType="slide" transparent><View style={st.back}><View style={st.modal}><Text style={st.modalTitle}>{edit?'تعديل':'إضافة'} {sec.title}</Text><ScrollView>{sec.fields.map((f:any)=><View key={f[0]} style={st.group}><Text style={st.label}>{f[1]}</Text><TextInput value={form[f[0]]||''} onChangeText={t=>setForm((c:any)=>({...c,[f[0]]:t}))} placeholder={f[2]==='date'?'YYYY-MM-DD':f[1]} keyboardType={f[2]==='number'?'decimal-pad':'default'} style={st.input} textAlign="right"/></View>)}</ScrollView><View style={st.actions}><Pressable onPress={()=>setOpen(false)} style={st.secondary}><Text style={st.secondaryText}>إلغاء</Text></Pressable><Pressable onPress={save} style={st.primary}><Text style={st.primaryText}>حفظ</Text></Pressable></View></View></View></Modal></View>}
function Card(p:any){return <View style={st.card}><Text style={st.k}>{p.title}</Text><Text style={st.big}>{p.value}</Text></View>}
const st=StyleSheet.create({screen:{flex:1,backgroundColor:'#f8fafc',paddingTop:54},head:{paddingHorizontal:20,paddingBottom:12,alignItems:'flex-end'},title:{fontSize:34,fontWeight:'900',color:'#0f172a'},sub:{fontSize:14,color:'#64748b'},tabs:{gap:8,paddingHorizontal:16,paddingBottom:12},tab:{paddingHorizontal:14,paddingVertical:10,borderRadius:18,backgroundColor:'#e2e8f0'},tabOn:{backgroundColor:'#0f172a'},tabText:{color:'#334155',fontWeight:'700'},tabTextOn:{color:'#fff'},bar:{padding:16,flexDirection:'row',justifyContent:'space-between',alignItems:'center'},h:{fontSize:20,fontWeight:'900',color:'#0f172a',textAlign:'right'},url:{fontSize:10,color:'#64748b',textAlign:'right'},add:{backgroundColor:'#16a34a',paddingHorizontal:14,paddingVertical:10,borderRadius:16},addText:{color:'#fff',fontWeight:'900'},loading:{flex:1,alignItems:'center',justifyContent:'center'},content:{padding:16,gap:12},empty:{textAlign:'center',color:'#94a3b8',marginTop:40},card:{backgroundColor:'#fff',borderRadius:22,padding:16,borderWidth:1,borderColor:'#e2e8f0'},row:{flexDirection:'row',justifyContent:'space-between',gap:12,paddingVertical:5},k:{color:'#64748b',fontSize:12},v:{color:'#0f172a',fontWeight:'700',flex:1,textAlign:'right'},big:{color:'#0f172a',fontSize:24,fontWeight:'900',textAlign:'right',marginTop:8},actions:{flexDirection:'row',gap:10,marginTop:14},primary:{flex:1,backgroundColor:'#0f172a',paddingVertical:12,borderRadius:15,alignItems:'center'},primaryText:{color:'#fff',fontWeight:'900'},secondary:{flex:1,backgroundColor:'#e2e8f0',paddingVertical:12,borderRadius:15,alignItems:'center'},secondaryText:{color:'#0f172a',fontWeight:'900'},back:{flex:1,backgroundColor:'rgba(15,23,42,.35)',justifyContent:'flex-end'},modal:{maxHeight:'86%',backgroundColor:'#fff',borderTopLeftRadius:28,borderTopRightRadius:28,padding:18},modalTitle:{fontSize:20,fontWeight:'900',color:'#0f172a',textAlign:'right',marginBottom:12},group:{marginBottom:12},label:{textAlign:'right',color:'#475569',marginBottom:6,fontWeight:'700'},input:{backgroundColor:'#f8fafc',borderWidth:1,borderColor:'#e2e8f0',borderRadius:16,paddingHorizontal:14,paddingVertical:12,color:'#0f172a'}});
EOF
cd "$APP_DIR"
npm install || true
chown -R pmsa:pmsa "$APP_DIR" || true
